    int sSize;
    int maxMove;
    fp alpha;

    int endoPoints;
    int d_endo_mem;
    int* d_endoRow;
    int* d_endoCol;
    int* d_tEndoRowLoc;
    int* d_tEndoColLoc;
    fp* d_endoT;

    int epiPoints;
    int d_epi_mem;
    int* d_epiRow;
    int* d_epiCol;
    int* d_tEpiRowLoc;
    int* d_tEpiColLoc;
    fp* d_epiT;

    int allPoints;

    fp* d_frames;
    int frames;
    int frame_no;
    fp* d_frame;
    int frame_rows;
    int frame_cols;
    int frame_elem;
    int frame_mem;

    int in2_rows;
    int in2_cols;
    int in2_elem;
